import { useState, useEffect } from "react"
import API from "../services/api"

export default function Quiz() {

    const [selectedSubject, setSelectedSubject] = useState("")
    const [questionCount, setQuestionCount] = useState(10)

    const [questions, setQuestions] = useState([])
    const [answers, setAnswers] = useState([])

    const [quizStarted, setQuizStarted] = useState(false)

    const [attempts, setAttempts] = useState([])

    const subjects = [
        "Python",
        "Java",
        "SQL",
        "Aptitude",
        "Reasoning",
        "Web Development",
        "HTML",
        "CSS",
        "JavaScript",
        "C",
        "C++"
    ]

    const fetchAttempts = async () => {

        try {

            const token = localStorage.getItem("token")

            const res = await API.get(
                "/quiz/my-attempts",
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            )

            setAttempts(res.data)

        } catch (error) {

            console.log(error)

        }

    }

    useEffect(() => {

        fetchAttempts()

    }, [])

    const startQuiz = async () => {

        try {

            const token = localStorage.getItem("token")

            const res = await API.get(
                `/quiz/questions?subject=${selectedSubject}`,
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            )

            let fetchedQuestions = [...res.data]

            while (fetchedQuestions.length < questionCount) {

                fetchedQuestions = [
                    ...fetchedQuestions,
                    ...res.data
                ]

            }

            fetchedQuestions =
                fetchedQuestions.slice(0, questionCount)

            setQuestions(fetchedQuestions)

            setAnswers([])

            setQuizStarted(true)

        } catch (error) {

            console.log(error)

        }
    }

    const handleAnswer = (index, option) => {

        const newAnswers = [...answers]

        newAnswers[index] = option

        setAnswers(newAnswers)
    }

    const submitQuiz = async () => {

        try {

            const token = localStorage.getItem("token")

            const res = await API.post(

                "/quiz/submit",

                {

                    subject: selectedSubject,

                    answers

                },

                {

                    headers: {

                        Authorization: `Bearer ${token}`

                    }

                }

            )

            alert(
                `Score: ${res.data.score}\nPercentage: ${res.data.percentage}%`
            )

            setQuizStarted(false)

            fetchAttempts()

        } catch (error) {

            console.log(error)

        }
    }

    return (

        <div
            style={{
                minHeight: "100vh",
                background: "#f4f6f9",
                padding: "30px"
            }}
        >

            {!quizStarted ? (

                <div
                    style={{
                        maxWidth: "700px",
                        margin: "auto",
                        background: "white",
                        padding: "30px",
                        borderRadius: "15px",
                        boxShadow: "0 4px 12px rgba(0,0,0,0.1)"
                    }}
                >

                    <h1
                        style={{
                            textAlign: "center",
                            marginBottom: "30px"
                        }}
                    >
                        Career Quiz
                    </h1>

                    <label>Select Subject</label>

                    <select
                        value={selectedSubject}
                        onChange={(e) =>
                            setSelectedSubject(e.target.value)
                        }
                        style={{
                            width: "100%",
                            padding: "10px",
                            marginTop: "10px",
                            marginBottom: "20px"
                        }}
                    >

                        <option value="">
                            Choose Subject
                        </option>

                        {subjects.map(subject => (

                            <option
                                key={subject}
                                value={subject}
                            >
                                {subject}
                            </option>

                        ))}

                    </select>

                    <label>
                        Number Of Questions
                    </label>

                    <select
                        value={questionCount}
                        onChange={(e) =>
                            setQuestionCount(
                                Number(e.target.value)
                            )
                        }
                        style={{
                            width: "100%",
                            padding: "10px",
                            marginTop: "10px"
                        }}
                    >

                        <option value={10}>
                            10 Questions
                        </option>

                        <option value={30}>
                            30 Questions
                        </option>

                        <option value={50}>
                            50 Questions
                        </option>

                    </select>

                    <button
                        onClick={startQuiz}
                        disabled={!selectedSubject}
                        style={{
                            width: "100%",
                            marginTop: "30px",
                            padding: "12px",
                            background: "#2563eb",
                            color: "white",
                            border: "none",
                            borderRadius: "8px",
                            cursor: "pointer"
                        }}
                    >
                        Start Quiz
                    </button>

                    <hr
                        style={{
                            marginTop: "40px",
                            marginBottom: "30px"
                        }}
                    />

                    <h2>
                        Previous Attempts
                    </h2>

                    {
                        attempts.length > 0 ? (

                            attempts.map((attempt, index) => (

                                <div
                                    key={index}
                                    style={{
                                        background: "#f8fafc",
                                        padding: "15px",
                                        marginTop: "10px",
                                        borderRadius: "10px",
                                        border: "1px solid #ddd"
                                    }}
                                >

                                    <p>
                                        <strong>Subject:</strong>
                                        {" "}
                                        {attempt.subject}
                                    </p>

                                    <p>
                                        <strong>Score:</strong>
                                        {" "}
                                        {attempt.score}/
                                        {attempt.totalQuestions}
                                    </p>

                                    <p>
                                        <strong>Percentage:</strong>
                                        {" "}
                                        {attempt.percentage}%
                                    </p>

                                    <p>
                                        <strong>Date:</strong>
                                        {" "}
                                        {new Date(
                                            attempt.createdAt
                                        ).toLocaleDateString()}
                                    </p>

                                </div>

                            ))

                        ) : (

                            <p>
                                No quiz attempts yet.
                            </p>

                        )
                    }

                </div>

            ) : (

                <div
                    style={{
                        maxWidth: "900px",
                        margin: "auto"
                    }}
                >

                    <h2>
                        {selectedSubject} Quiz
                    </h2>

                    <p>
                        Total Questions:
                        {" "}
                        {questions.length}
                    </p>

                    {questions.map((q, index) => (

                        <div
                            key={index}
                            style={{
                                background: "white",
                                padding: "20px",
                                borderRadius: "12px",
                                marginBottom: "20px",
                                boxShadow:
                                    "0 2px 8px rgba(0,0,0,0.1)"
                            }}
                        >

                            <h4>
                                Q{index + 1}. {q.question}
                            </h4>

                            {q.options.map((opt, i) => (

                                <div
                                    key={i}
                                    style={{
                                        marginTop: "10px"
                                    }}
                                >

                                    <label>

                                        <input
                                            type="radio"
                                            name={`question-${index}`}
                                            checked={
                                                answers[index] === opt
                                            }
                                            onChange={() =>
                                                handleAnswer(
                                                    index,
                                                    opt
                                                )
                                            }
                                        />

                                        {" "}
                                        {opt}

                                    </label>

                                </div>

                            ))}

                        </div>

                    ))}

                    <button
                        onClick={submitQuiz}
                        style={{
                            width: "100%",
                            padding: "14px",
                            background: "#16a34a",
                            color: "white",
                            border: "none",
                            borderRadius: "8px",
                            fontSize: "16px"
                        }}
                    >
                        Submit Quiz
                    </button>

                </div>

            )}

        </div>

    )
}
